const scheduleMaintenance = `-- name: ScheduleMaintenance :exec
UPDATE inventory.equipment
SET next_maintenance_at = $3,
    updated_at = CURRENT_TIMESTAMP
WHERE id = $1
    AND tenant_id = $2
`

func (q *Queries) ScheduleMaintenance(ctx context.Context, iD pgtype.UUID, tenantID pgtype.UUID, nextMaintenanceAt pgtype.Timestamptz) error {
	_, err := q.db.Exec(ctx, scheduleMaintenance, iD, tenantID, nextMaintenanceAt)
	return err
}

